export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const id = url.pathname.match(/^\/api\/todos\/(\d+)$/);
    const cors = {
      "Access-Control-Allow-Origin": "*",
      "Access-Control-Allow-Methods": "GET,POST,PUT,DELETE,OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type"
    };

    if (request.method === "OPTIONS") return new Response(null, { headers: cors });

    try {
      // READ: list every todo
      if (url.pathname === "/api/todos" && request.method === "GET") {
        const { results } = await env.DB
          .prepare("SELECT * FROM todos ORDER BY created_at DESC")
          .all();
        return json(results, 200, cors);
      }

      // CREATE: insert one todo
      if (url.pathname === "/api/todos" && request.method === "POST") {
        const { title } = await request.json();
        if (!title) return json({ error: "title required" }, 400, cors);
        const row = await env.DB
          .prepare("INSERT INTO todos (title) VALUES (?) RETURNING *")
          .bind(title)
          .first();
        return json(row, 201, cors);
      }

      // UPDATE: toggle done or edit title
      if (id && request.method === "PUT") {
        const { title, done } = await request.json();
        const row = await env.DB
          .prepare("UPDATE todos SET title = COALESCE(?, title), done = COALESCE(?, done) WHERE id = ? RETURNING *")
          .bind(title ?? null, done ?? null, Number(id[1]))
          .first();
        return row ? json(row, 200, cors) : json({ error: "not found" }, 404, cors);
      }

      // DELETE: remove one todo
      if (id && request.method === "DELETE") {
        const info = await env.DB
          .prepare("DELETE FROM todos WHERE id = ?")
          .bind(Number(id[1]))
          .run();
        return json({ deleted: info.meta.changes }, 200, cors);
      }

      return json({ error: "not found" }, 404, cors);
    } catch (err) {
      return json({ error: err.message }, 500, cors);
    }
  }
};

function json(data, status, cors) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json", ...cors }
  });
}

const API = "https://todo-api.<your-subdomain>.workers.dev/api/todos";

// READ — GET all todos
export async function listTodos() {
  const res = await fetch(API);
  return res.json();
}

// CREATE — POST a new todo
export async function addTodo(title) {
  const res = await fetch(API, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ title })
  });
  return res.json();
}

// UPDATE — PUT to toggle done (or edit title)
export async function toggleTodo(id, done) {
  const res = await fetch(`${API}/${id}`, {
    method: "PUT",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ done })
  });
  return res.json();
}

// DELETE — remove a todo
export async function removeTodo(id) {
  const res = await fetch(`${API}/${id}`, { method: "DELETE" });
  return res.json();
}
